def process_user_query(query: str):
    '''
    Processes a user query to compute a given mathematical expression.
    Permits only numbers and basic arithmetic operators (+, -, *, /).
    '''
    # Security: Use a strict regex to ensure only allowed characters are present
    if not re.match(r'^[0-9.+\-*/() \s]*$', query):
        return "Error: Invalid characters in expression"

    # Mapping AST nodes to operator functions
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def _eval(node):
        # Handle numeric constants (Python 3.8+)
        if isinstance(node, ast.Constant):
            if not isinstance(node.value, (int, float)):
                raise TypeError("Only numeric constants are allowed")
            return node.value
        # Handle numeric constants (Python < 3.8)
        elif isinstance(node, ast.Num):
            return node.n
        # Handle binary operations (+, -, *, /)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type}")
            return operators[op_type](_eval(node.left), _eval(node.right))
        # Handle unary operations (e.g., -1)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type}")
            return operators[op_type](_eval(node.operand))
        else:
            raise TypeError(f"Unsupported expression component: {type(node)}")

    try:
        # Parse the query into an Abstract Syntax Tree (AST) in 'eval' mode
        # This ensures the input is a single expression and not multiple statements
        tree = ast.parse(query, mode='eval')
        return _eval(tree.body)
    except ZeroDivisionError:
        return "Error: Division by zero"
    except (SyntaxError, TypeError, KeyError) as e:
        return f"Error: {str(e)}"
    except Exception:
        return "Error: An unexpected error occurred during evaluation"

